select count(*) from custo; 
select * from custo limit 20;       



-- Q1. What is the total revenue generated by male vs. female customers?

select gender, sum(purchase_amount) as Revenue
from custo
group by gender
order by Revenue;



-- Q2. Which customers used a discount but still spent more than the average purchase amount?

select customer_id, discount_applied, purchase_amount
from custo
where discount_applied = 'Yes' and purchase_amount >
(
  select avg(purchase_amount) from custo);



-- Q3. Which are the top 5 products with the highest average review rating?

select item_purchased, avg(review_rating) as Avarage_Rating
from custo
group by item_purchased
order by Avarage_Rating desc
limit 5;



-- Q4. Compare the average Purchase Amounts between Standard and Express Shipping.

select  shipping_type, avg(purchase_amount) 
from custo
where shipping_type in ('Standard','Express') 
group by shipping_type;



-- Q5. Do subscribed customers spend more? Compare average spend and total revenue between subscribers and non-subscribers.

select subscription_status, count(customer_id) as Total_Customers,
round(avg(purchase_amount),2) as Average_spend, sum(purchase_amount) as Total_Spend
from custo
group by subscription_status
order by Average_spend;



--Q6. Which 5 products have the highest percentage of purchases amount with 
--discounts applied? (Total number of time, item was sold)

select item_purchased, 
(100 * sum(case when discount_applied = 'Yes' then 1 else 0 end)/count(purchase_amount))as Total_percentage
from custo
group by item_purchased
order by Total_percentage desc
limit 5;



--Q7. Segment customers into New, Returning, and Loyal based on their total number of previous purchases, 
--and show the count of each segment.

with customer_type as 
(
select  customer_id, previous_purchases,
  case 
      when previous_purchases = 1 then 'New'
	  when previous_purchases between 2 and 20 then 'Returning'
	  else 'Loyal'
  end as Customer_Segment
from custo
)
select customer_segment, count(*) as Total_customer
from customer_type
group by customer_segment;



--Q8. What are the top 3 most purchased products within each category?

with typo as 
(
select item_purchased, category, count(customer_id) as total_count,
row_number() over (partition by category order by count(customer_id) desc) as item_rank
from custo
group by item_purchased, category
)

select total_count, item_purchased, category, item_rank
from typo
where item_rank <=3;



--09. Are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe?

select subscription_status, count(customer_id)
from custo
where previous_purchases > 5
group by subscription_status;



--Q10. What is the revenue contribution of each age group?

select age_group, sum(purchase_amount) as Total_Revenue
from custo
group by age_group
order by Total_Revenue desc;

